import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"Track orders placed through third-party marketplaces","description":"Notes on Track orders placed through third-party marketplaces.","frontmatter":{"title":"Track orders placed through third-party marketplaces","description":"Notes on Track orders placed through third-party marketplaces."},"headers":[],"relativePath":"software-engineering/shopify-dev/track-orders-placed-through-third-party-marketplaces.md","filePath":"software-engineering/shopify-dev/track-orders-placed-through-third-party-marketplaces.md"}'),d={name:"software-engineering/shopify-dev/track-orders-placed-through-third-party-marketplaces.md"};function l(i,e,s,c,n,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="track-orders-placed-through-third-party-marketplaces" tabindex="-1">Track orders placed through third-party marketplaces <a class="header-anchor" href="#track-orders-placed-through-third-party-marketplaces" aria-label="Permalink to &quot;Track orders placed through third-party marketplaces&quot;">​</a></h1><p>Orders created through third-party marketplaces (Facebook, Google, etc.) use <strong>Shopify Payments</strong> as the processor. Fulfillment and payment capture behave differently from other channels.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://shopify.dev/docs/apps/fulfillment/order-management-apps/third-party-marketplaces" target="_blank" rel="noreferrer">Track orders placed on other platforms</a> — Shopify developer docs</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>App can make authenticated <strong>GraphQL Admin API</strong> requests</li><li>Store has unfulfilled orders to test against</li><li>Familiarity with <code>FulfillmentOrder</code> objects</li><li><a href="https://shopify.dev/docs/apps/launch/protected-customer-data" target="_blank" rel="noreferrer">Protected customer data requirements</a> met</li></ul><h2 id="how-marketplace-orders-differ" tabindex="-1">How marketplace orders differ <a class="header-anchor" href="#how-marketplace-orders-differ" aria-label="Permalink to &quot;How marketplace orders differ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Third-party marketplace</th><th>Other channels</th></tr></thead><tbody><tr><td>Transaction capture</td><td>After fulfillment (marketplace initiates capture)</td><td>Often captured before fulfillment</td></tr><tr><td>Immediate fulfillment</td><td><strong>No</strong> — hold period ~30 min–24 h</td><td>Usually allowed immediately</td></tr><tr><td>During hold</td><td>Cannot change address, edit order, issue custom refunds, or manually capture</td><td>Normal order ops</td></tr></tbody></table><p>Hold period covers cancellation windows, payment authorization, and fraud review.</p><h2 id="recommended-workflow" tabindex="-1">Recommended workflow <a class="header-anchor" href="#recommended-workflow" aria-label="Permalink to &quot;Recommended workflow&quot;">​</a></h2><h3 id="_1-use-fulfillment-orders-not-legacy-fulfillment-api" tabindex="-1">1. Use fulfillment orders (not legacy Fulfillment API) <a class="header-anchor" href="#_1-use-fulfillment-orders-not-legacy-fulfillment-api" aria-label="Permalink to &quot;1. Use fulfillment orders (not legacy Fulfillment API)&quot;">​</a></h3><p>As of API <strong>2022-07</strong>, fulfill via <code>FulfillmentOrder</code> — not legacy <code>Order</code> + <code>Fulfillment</code> objects. Migrate before <strong>2023-07</strong>.</p><h3 id="_2-identify-the-source-channel" tabindex="-1">2. Identify the source channel <a class="header-anchor" href="#_2-identify-the-source-channel" aria-label="Permalink to &quot;2. Identify the source channel&quot;">​</a></h3><p>Review fields when fetching an order:</p><table tabindex="0"><thead><tr><th>Field</th><th>Shopify Payments</th><th>Facebook Payments</th></tr></thead><tbody><tr><td><code>displayFulfillmentStatus</code></td><td><code>ON_HOLD</code></td><td><code>UNFULFILLED</code></td></tr><tr><td><code>displayFinancialStatus</code></td><td><code>AUTHORIZED</code></td><td><code>PAID</code></td></tr><tr><td><code>paymentGatewayNames</code></td><td><code>[&quot;shopify_payments&quot;]</code></td><td><code>[&quot;instagram&quot;]</code></td></tr></tbody></table><p>Use <code>source_name</code> (set at order creation only) to determine channel — <strong>not</strong> <code>gateway</code>, which may show <code>shopify_payments</code> even for Facebook-channel orders.</p><h3 id="_3-decide-if-the-order-is-fulfillable" tabindex="-1">3. Decide if the order is fulfillable <a class="header-anchor" href="#_3-decide-if-the-order-is-fulfillable" aria-label="Permalink to &quot;3. Decide if the order is fulfillable&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Check</th><th>Value</th><th>Webhook hints</th></tr></thead><tbody><tr><td><code>Order.displayFinancialStatus</code></td><td><code>AUTHORIZED</code> or <code>PAID</code></td><td><code>orders/updated</code></td></tr><tr><td><code>FulfillmentOrder.status</code></td><td><code>OPEN</code></td><td><code>fulfillment_orders/order_routing_complete</code>, <code>fulfillment_orders/scheduled_fulfillment_order_ready</code>, <code>fulfillment_orders/hold_released</code></td></tr></tbody></table><blockquote><p><strong>Note:</strong> <code>line_items.fulfillable_quantity</code> is <code>0</code> when a fulfillment order is on hold — do not use it alone. Check <code>FulfillmentOrder.status</code> before creating a fulfillment after <code>order/create</code>.</p></blockquote><h2 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h2><ul><li><strong>Do not</strong> start fulfillments solely on <code>orders/create</code>, <code>order_transactions/create</code>, or <code>order/paid</code> — use <code>fulfillment_orders/ready_to_fulfill</code> (unstable API) and inspect <code>FulfillmentOrder</code> status.</li><li>During the Facebook Payments → Shopify Payments transition, branch on <code>paymentGatewayNames</code> / gateway until all stores are migrated.</li><li>Avoid fixed hold-duration assumptions — marketplace hold times vary.</li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="https://shopify.dev/docs/apps/fulfillment/order-management-apps" target="_blank" rel="noreferrer">Manage fulfillments as an order management app</a></li><li><a href="https://shopify.dev/docs/apps/fulfillment/migrate-to-fulfillment-orders" target="_blank" rel="noreferrer">Migrate to fulfillment orders</a></li></ul>',23)])])}const p=t(d,[["render",l]]);export{u as __pageData,p as default};
